//! Conformance: secp-native must reproduce every @bsv/sdk-generated vector in
//! fixtures/vectors.json BYTE-FOR-BYTE. This file is the PoC's proof artifact.
//!
//! Vectors were generated by scripts/gen-vectors.mjs against the PUBLISHED
//! @bsv/sdk@2.1.6 (the exact package bsv-browser locks) and cross-checked identical
//! against the TypeScript ts-sdk HEAD (2.1.8). Nothing real was signed —
//! all keys/messages are sha256-of-label synthetics.

use secp_native::*;
use serde::Deserialize;

#[derive(Deserialize)]
struct Vectors {
    sign: Vec<SignVector>,
    brc42: Vec<Brc42Vector>,
    ecdh: Vec<EcdhVector>,
    tweak: Vec<TweakVector>,
    recover: Vec<RecoverVector>,
    #[serde(rename = "tweakMul")]
    tweak_mul: Vec<TweakMulVector>,
    combine: Vec<CombineVector>,
    #[serde(rename = "schnorrAccept")]
    schnorr_accept: Vec<SchnorrAcceptVector>,
    #[serde(rename = "schnorrReject")]
    schnorr_reject: Vec<SchnorrRejectVector>,
    #[serde(rename = "batchSign")]
    batch_sign: Vec<BatchSignVector>,
    #[serde(rename = "batchVerify")]
    batch_verify: BatchVerifyVectors,
    #[serde(rename = "batchDerive")]
    batch_derive: BatchDeriveVector,
    uncompressed: UncompressedVector,
}

