fn load() -> Vectors {
    let path = concat!(env!("CARGO_MANIFEST_DIR"), "/fixtures/vectors.json");
    serde_json::from_str(&std::fs::read_to_string(path).expect("fixtures/vectors.json"))
        .expect("parse vectors.json")
}

fn h(s: &str) -> Vec<u8> {
    hex::decode(s).unwrap()
}

/// Sign class: pubkey_create AND the DER signature must match the SDK byte-for-byte
/// (RFC 6979 nonces on both sides — see lib.rs header). Also proves verify-compat in
/// both directions: byte-equality makes "Rust sig verifies in SDK" identical to the
/// SDK self-verify already asserted at generation time, and we explicitly verify the
/// SDK's DER sig with Rust here.
#[test]
fn sign_vectors_exact_match() {
    let v = load();
    assert!(!v.sign.is_empty());
    for (i, t) in v.sign.iter().enumerate() {
        let pk = pubkey_create(h(&t.privkey)).unwrap();
        assert_eq!(hex::encode(&pk), t.pubkey, "sign[{i}] pubkey");
        let der = ecdsa_sign(h(&t.msg32), h(&t.privkey)).unwrap();
        assert_eq!(hex::encode(&der), t.der, "sign[{i}] DER (nonce/low-S mismatch?)");
        // SDK-produced sig verifies under Rust (redundant given byte-equality, kept
        // explicit so a future nonce divergence still leaves this compat assertion).
        assert!(ecdsa_verify(h(&t.msg32), h(&t.der), pk).unwrap(), "sign[{i}] verify SDK sig");
    }
}

/// BRC-42 class: shared point, HMAC tweak, derived privkey, derived pubkey — all
/// nonce-free, all byte-exact. Intermediates are asserted so a failure localizes.
#[test]
fn brc42_vectors_exact_match() {
    let v = load();
    assert!(!v.brc42.is_empty());
    for (i, t) in v.brc42.iter().enumerate() {
        let shared = ecdh_shared_point(h(&t.privkey), h(&t.counterparty_pub)).unwrap();
        assert_eq!(hex::encode(&shared), t.shared_point, "brc42[{i}] sharedPoint");
        let derived =
            brc42_derive_child(h(&t.privkey), h(&t.counterparty_pub), t.invoice_number.clone())
                .unwrap();
        assert_eq!(hex::encode(&derived), t.derived_priv, "brc42[{i}] derivedPriv");
        let derived_pub = pubkey_create(derived).unwrap();
        assert_eq!(hex::encode(&derived_pub), t.derived_pub, "brc42[{i}] derivedPub");
        // hmac tweak: recompute via privkey_tweak_add path equivalence:
        // derived == priv + hmacTweak (mod n)
        let via_tweak = privkey_tweak_add(h(&t.privkey), h(&t.hmac_tweak)).unwrap();
        assert_eq!(hex::encode(&via_tweak), t.derived_priv, "brc42[{i}] hmacTweak path");
        // and the PUBLIC side: counterpartyless pubkey_tweak_add(P, hmacTweak) == derivedPub
        let pub_side = pubkey_tweak_add(pubkey_create(h(&t.privkey)).unwrap(), h(&t.hmac_tweak))
            .unwrap();
        assert_eq!(hex::encode(&pub_side), t.derived_pub, "brc42[{i}] pubkey tweak path");
    }
}

/// ECDH class: compressed shared point byte-exact vs SDK deriveSharedSecret.
#[test]
fn ecdh_vectors_exact_match() {
    let v = load();
    assert!(!v.ecdh.is_empty());
    for (i, t) in v.ecdh.iter().enumerate() {
        let shared = ecdh_shared_point(h(&t.privkey), h(&t.pubkey)).unwrap();
        assert_eq!(hex::encode(&shared), t.shared_point, "ecdh[{i}]");
    }
}

/// secp256k1 field prime p minus group order n, as 32 BE bytes — the recid-2/3
/// asymmetry boundary (x = r + n overflows the field iff r >= p - n).
/// p - n = 0x14551231950b75fc4402da1722fc9baee (129 bits).
fn p_minus_n() -> [u8; 32] {
    let mut out = [0u8; 32];
    let tail = hex::decode("014551231950b75fc4402da1722fc9baee").unwrap();
    out[32 - tail.len()..].copy_from_slice(&tail);
    out
}

/// Recover class (issue #5): compact round-trip + recovery factor + per-recid
/// parity. recid 0/1 must match the SDK exactly (value ↔ value, null ↔ error).
/// recid 2/3: exact parity when r < p - n; otherwise the SDK reduces x = r + n
/// mod p (Point.fromX) and may fabricate a point while libsecp256k1 rejects the
/// field overflow — the native side MUST reject there (the app seam falls back
/// to pure JS, preserving SDK behavior; documented in src/lib.rs).
#[test]
fn recover_vectors_match() {
    let v = load();
    assert!(!v.recover.is_empty());
    let boundary = p_minus_n();
    for (i, t) in v.recover.iter().enumerate() {
        let compact = h(&t.compact);
        // full-compact recovery == the signing pubkey
        let pk = ecdsa_recover(h(&t.msg32), compact.clone()).unwrap();
        assert_eq!(hex::encode(&pk), t.pubkey, "recover[{i}] compact round-trip");
        // recovery factor search matches CalculateRecoveryFactor
        let rs64 = compact[1..].to_vec();
        let rec = ecdsa_recovery_factor(h(&t.msg32), rs64.clone(), h(&t.pubkey)).unwrap();
        assert_eq!(rec, t.recovery, "recover[{i}] recovery factor");
        // per-recid parity
        let r32: [u8; 32] = compact[1..33].try_into().unwrap();
        for recid in 0u8..4 {
            let mut c = vec![27 + 4 + recid];
            c.extend_from_slice(&rs64);
            let native = ecdsa_recover(h(&t.msg32), c);
            let sdk = &t.recovered_all_factors[recid as usize];
            if recid < 2 || r32 < boundary {
                match (sdk, native) {
                    (Some(exp), Ok(got)) => {
                        assert_eq!(hex::encode(got), *exp, "recover[{i}] recid {recid}")
                    }
                    (None, Err(_)) => {}
                    (s, n) => panic!(
                        "recover[{i}] recid {recid} parity broke: sdk={s:?} native_ok={}",
                        n.is_ok()
                    ),
                }
            } else {
                // documented asymmetry zone: native must reject the field overflow
                assert!(
                    native.is_err(),
                    "recover[{i}] recid {recid}: native accepted r + n >= p (must reject)"
                );
            }
        }
    }
}

