/// Schnorr accept class (issue #6): the challenge, the full generate output
/// (R ‖ S' ‖ z) and the verify verdict must all match the SDK byte-for-byte.
#[test]
fn schnorr_accept_vectors_exact_match() {
    let v = load();
    assert!(!v.schnorr_accept.is_empty());
    for (i, t) in v.schnorr_accept.iter().enumerate() {
        // challenge intermediate — localizes any hashing/serialization divergence
        let e = schnorr_challenge(
            &h(&t.a_pub), &h(&t.b_pub), &h(&t.s), &h(&t.s_prime), &h(&t.r_pub),
        );
        assert_eq!(hex::encode(e), t.e, "schnorr[{i}] challenge");
        // generate: byte-exact R33 ‖ S'33 ‖ z32 given the vector's nonce r
        let proof = schnorr_generate_proof(
            h(&t.a), h(&t.a_pub), h(&t.b_pub), h(&t.s), h(&t.r),
        )
        .unwrap();
        let expected = format!("{}{}{}", t.r_pub, t.s_prime, t.z);
        assert_eq!(hex::encode(&proof), expected, "schnorr[{i}] generate");
        // verify accepts
        assert!(
            schnorr_verify_proof(
                h(&t.a_pub), h(&t.b_pub), h(&t.s), h(&t.r_pub), h(&t.s_prime), h(&t.z),
            )
            .unwrap(),
            "schnorr[{i}] verify accept"
        );
    }
}

/// Schnorr reject class (issue #6): corrupted proofs the SDK rejects must be
/// rejected natively too (verdict parity — all fields well-formed by design).
#[test]
fn schnorr_reject_vectors_match() {
    let v = load();
    assert!(!v.schnorr_reject.is_empty());
    for (i, t) in v.schnorr_reject.iter().enumerate() {
        assert!(
            !schnorr_verify_proof(
                h(&t.a_pub), h(&t.b_pub), h(&t.s), h(&t.r_pub), h(&t.s_prime), h(&t.z),
            )
            .unwrap(),
            "schnorrReject[{i}] ({}) was ACCEPTED",
            t.label
        );
    }
}

/// Tweak class: (k+t) mod n and P+t·G byte-exact vs SDK BigNumber/Point math.
#[test]
fn tweak_vectors_exact_match() {
    let v = load();
    assert!(!v.tweak.is_empty());
    for (i, t) in v.tweak.iter().enumerate() {
        let priv_r = privkey_tweak_add(h(&t.privkey), h(&t.tweak)).unwrap();
        assert_eq!(hex::encode(&priv_r), t.priv_result, "tweak[{i}] priv");
        let pub_r = pubkey_tweak_add(h(&t.pubkey), h(&t.tweak)).unwrap();
        assert_eq!(hex::encode(&pub_r), t.pub_result, "tweak[{i}] pub");
    }
}

// ═══ M3 Tier-2 classes (issues #8/#9 — batch flows + uncompressed outputs) ═══

/// batchSign class: batch_ecdsa_sign over the whole vector set in ONE call must
/// produce, per element, the SDK's DER (forceLowS RFC 6979) AND the SDK's
/// compressed pubkey — i.e. the framed [derLen][der][pubkey33] layout carries
/// exactly ecdsa_sign(msg_i, key_i) ‖ pubkey_create(key_i).
#[test]
fn batch_sign_vectors_exact_match() {
    let v = load();
    assert!(!v.batch_sign.is_empty());
    let mut msgs = Vec::new();
    let mut keys = Vec::new();
    for t in &v.batch_sign {
        msgs.extend_from_slice(&h(&t.msg32));
        keys.extend_from_slice(&h(&t.privkey));
    }
    let framed = batch_ecdsa_sign(msgs, keys).unwrap();
    let mut off = 0usize;
    for (i, t) in v.batch_sign.iter().enumerate() {
        let len = framed[off] as usize;
        let der = &framed[off + 1..off + 1 + len];
        let pk = &framed[off + 1 + len..off + 1 + len + 33];
        assert_eq!(hex::encode(der), t.der, "batchSign[{i}] der");
        assert_eq!(hex::encode(pk), t.pubkey, "batchSign[{i}] pubkey");
        off += 1 + len + 33;
    }
    assert_eq!(off, framed.len(), "batchSign framing consumed exactly");
}

/// batchVerify class: batch_ecdsa_verify verdicts must equal the SDK's verify
/// verdict per element for both the all-valid and the corrupted sets.
#[test]
fn batch_verify_vectors_match() {
    let v = load();
    for (set_name, set) in [("valid", &v.batch_verify.valid), ("corrupted", &v.batch_verify.corrupted)] {
        assert!(!set.is_empty());
        let mut msgs = Vec::new();
        let mut sigs = Vec::new();
        let mut pubs = Vec::new();
        for t in set.iter() {
            msgs.extend_from_slice(&h(&t.msg32));
            let der = h(&t.der);
            sigs.push(der.len() as u8);
            sigs.extend_from_slice(&der);
            pubs.extend_from_slice(&h(&t.pubkey));
        }
        let verdicts = batch_ecdsa_verify(msgs, sigs, pubs).unwrap();
        for (i, t) in set.iter().enumerate() {
            assert_eq!(verdicts[i] == 1, t.valid, "batchVerify {set_name}[{i}]");
        }
    }
}

/// batchDerive class: ONE root + ONE counterparty + N invoices. The priv-side
/// batch must equal PrivateKey.deriveChild per element; the pub-side
/// uncompressed batch must equal PublicKey.deriveChild(...).encode(false).
#[test]
fn batch_derive_vectors_exact_match() {
    let v = load();
    let d = &v.batch_derive;
    assert!(!d.invoice_numbers.is_empty());
    let privs = batch_brc42_derive_child(
        h(&d.root),
        h(&d.counterparty_pub),
        d.invoice_numbers.clone(),
    )
    .unwrap();
    let pubs = batch_brc42_derive_child_pub_uncompressed(
        h(&d.counterparty_priv),
        h(&d.root_pub),
        d.invoice_numbers.clone(),
    )
    .unwrap();
    for (i, _) in d.invoice_numbers.iter().enumerate() {
        assert_eq!(
            hex::encode(&privs[i * 32..(i + 1) * 32]),
            d.derived_privs[i],
            "batchDerive priv[{i}]"
        );
        assert_eq!(
            hex::encode(&pubs[i * 65..(i + 1) * 65]),
            d.derived_pubs_uncompressed[i],
            "batchDerive pub[{i}]"
        );
        // element-wise equality with the proven single-op composites
        assert_eq!(
            privs[i * 32..(i + 1) * 32].to_vec(),
            brc42_derive_child(h(&d.root), h(&d.counterparty_pub), d.invoice_numbers[i].clone())
                .unwrap(),
            "batchDerive priv[{i}] == per-op"
        );
        assert_eq!(
            pubs[i * 65..(i + 1) * 65].to_vec(),
            brc42_derive_child_pub_uncompressed(
                h(&d.counterparty_priv),
                h(&d.root_pub),
                d.invoice_numbers[i].clone()
            )
            .unwrap(),
            "batchDerive pub[{i}] == per-op"
        );
    }
}

/// uncompressed class: every *_uncompressed variant must equal the SDK's
/// encode(false) output byte-for-byte (0x04‖x‖y — no JS decompression needed).
#[test]
fn uncompressed_vectors_exact_match() {
    let v = load();
    let u = &v.uncompressed;
    assert_eq!(
        hex::encode(pubkey_create_uncompressed(h(&u.privkey)).unwrap()),
        u.pubkey_create,
        "pubkey_create_uncompressed"
    );
    assert_eq!(
        hex::encode(ecdh_shared_point_uncompressed(h(&u.privkey), h(&u.pubkey)).unwrap()),
        u.ecdh_shared_point,
        "ecdh_shared_point_uncompressed"
    );
    assert_eq!(
        hex::encode(pubkey_tweak_add_uncompressed(h(&u.pubkey), h(&u.tweak)).unwrap()),
        u.tweak_add,
        "pubkey_tweak_add_uncompressed"
    );
    assert_eq!(
        hex::encode(ecdsa_recover_uncompressed(h(&u.msg32), h(&u.compact)).unwrap()),
        u.recovered,
        "ecdsa_recover_uncompressed"
    );
}
